#include <stdio.h>
#include <string.h>
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <sys/wait.h>
#include <unistd.h>

#define CAP 4
#define MSG_LEN 32

typedef struct {
    char slots[CAP][MSG_LEN];
    int head;
    int tail;
    int count;
} RingBuf;

void rb_push(RingBuf *rb, const char *msg) {
    strncpy(rb->slots[rb->____], msg, MSG_LEN - 1);
    rb->tail = (rb->tail + 1) % ____;
    rb->count++;
}

const char *rb_pop(RingBuf *rb) {
    const char *msg = rb->slots[rb->____];
    rb->head = (rb->head + 1) % CAP;
    rb->count--;
    return msg;
}

int main(void) {
    int fd = shm_open("/kf_shm_ring", O_CREAT | O_RDWR, 0644);
    ftruncate(fd, sizeof(RingBuf));
    RingBuf *rb = (RingBuf *)mmap(NULL, sizeof(RingBuf),
        PROT_READ | PROT_WRITE, MAP_SHARED, fd, 0);
    close(fd);
    memset(rb, 0, sizeof(RingBuf));

    if (fork() == 0) {
        rb_push(rb, "msg-A");
        rb_push(rb, "msg-B");
        rb_push(rb, "msg-C");
        _exit(0);
    }
    wait(NULL);

    while (rb->count > 0)
        printf("Pop: %s\n", rb_pop(rb));

    munmap(rb, sizeof(RingBuf));
    shm_unlink("/kf_shm_ring");
    return 0;
}

